 14→mod lifecycle {
 15→    use spacetimedb::{ReducerContext, Table};
 16→
 17→    use crate::tables::{
 18→        channel, server, server_member, user_presence, user_profile, Channel, Server, ServerMember,
 19→        UserPresence, UserProfile,
 20→    };
 21→    use crate::types::{ChannelType, MemberRole};
 22→
 23→    #[spacetimedb::reducer(init)]
 24→    pub fn init(ctx: &ReducerContext) {
 25→        // Create the default "Spaces Hub" server
 26→        let hub = ctx.db.server().insert(Server {
 27→            id: 0,
 28→            name: "Spaces Hub".to_string(),
 29→            description: Some("Default server for the Spaces network".to_string()),
 30→            icon_url: None,
 31→            owner: ctx.sender(),
 32→            created_at: ctx.timestamp,
 33→        });
 34→
 35→        // Create default channels
 36→        ctx.db.channel().insert(Channel {
 37→            id: 0,
 38→            server_id: hub.id,
 39→            name: "general".to_string(),
 40→            topic: Some("General discussion".to_string()),
 41→            channel_type: ChannelType::Text,
 42→            position: 0,
 43→            created_at: ctx.timestamp,
 44→        });
 45→
 46→        ctx.db.channel().insert(Channel {
 47→            id: 0,
 48→            server_id: hub.id,
 49→            name: "agent-logs".to_string(),
 50→            topic: Some("Agent activity logs".to_string()),
 51→            channel_type: ChannelType::AgentLog,
 52→            position: 1,
 53→            created_at: ctx.timestamp,
 54→        });
 55→
 56→        ctx.db.channel().insert(Channel {
 57→            id: 0,
 58→            server_id: hub.id,
 59→            name: "system".to_string(),
 60→            topic: Some("System notifications".to_string()),
 61→            channel_type: ChannelType::Announcement,
 62→            position: 2,
 63→            created_at: ctx.timestamp,
 64→        });
 65→
 66→        log::info!("Spaces Hub initialized with id={}", hub.id);
 67→    }
 68→
 69→    #[spacetimedb::reducer(client_connected)]
 70→    pub fn client_connected(ctx: &ReducerContext) {
 71→        let sender = ctx.sender();
 72→
 73→        // Upsert UserPresence
 74→        if let Some(presence) = ctx.db.user_presence().identity().find(sender) {
 75→            ctx.db.user_presence().identity().update(UserPresence {
 76→                online: true,
 77→                last_seen: ctx.timestamp,
 78→                ..presence
 79→            });
 80→        } else {
 81→            ctx.db.user_presence().insert(UserPresence {
 82→                identity: sender,
 83→                online: true,
 84→                status_text: None,
 85→                last_seen: ctx.timestamp,
 86→            });
 87→        }
 88→
 89→        // Create UserProfile if new
 90→        if ctx.db.user_profile().identity().find(sender).is_none() {
 91→            let short_id = sender.to_hex().to_string();
 92→            let username = format!("user_{}", &short_id[..8.min(short_id.len())]);
 93→
 94→            ctx.db.user_profile().insert(UserProfile {
 95→                identity: sender,
 96→                username,
 97→                display_name: None,
 98→                avatar_url: None,
 99→                bio: None,
100→                is_agent: false,
101→                created_at: ctx.timestamp,
102→            });
103→
104→            // Auto-join the Spaces Hub (first server, id=1 typically)
105→            // Find the Spaces Hub by name
106→            if let Some(hub) = ctx.db.server().iter().find(|s| s.name == "Spaces Hub") {
107→                // Only join if not already a member
108→                let already_member = ctx
109→                    .db
110→                    .server_member()
111→                    .server_id()
112→                    .filter(&hub.id)
113→                    .any(|m| m.identity == sender);
114→                if !already_member {
115→                    ctx.db.server_member().insert(ServerMember {
116→                        id: 0,
117→                        server_id: hub.id,
118→                        identity: sender,
119→                        role: MemberRole::Member,
120→                        joined_at: ctx.timestamp,
121→                    });
122→                }
123→            }
124→        }
125→
126→        log::info!("Client connected: {:?}", sender);
127→    }
128→
129→    #[spacetimedb::reducer(client_disconnected)]
130→    pub fn client_disconnected(ctx: &ReducerContext) {
131→        if let Some(presence) = ctx.db.user_presence().identity().find(ctx.sender()) {
132→            ctx.db.user_presence().identity().update(UserPresence {
133→                online: false,
134→                last_seen: ctx.timestamp,
135→                ..presence
136→            });
137→        }
138→        log::info!("Client disconnected: {:?}", ctx.sender());
139→    }
140→}
