  1→use crate::port::SpacesPort;
  2→use arcan_core::error::CoreError;
  3→use arcan_core::protocol::{ToolAnnotations, ToolCall, ToolDefinition, ToolResult};
  4→use arcan_core::runtime::Tool;
  5→use arcan_core::runtime::ToolContext;
  6→use serde_json::{Value, json};
  7→use std::sync::Arc;
  8→
  9→const MAX_CONTENT_LENGTH: usize = 4000;
 10→
 11→fn validate_content(content: &str, tool_name: &str) -> Result<(), CoreError> {
 12→    if content.is_empty() {
 13→        return Err(CoreError::ToolExecution {
 14→            tool_name: tool_name.to_string(),
 15→            message: "content must not be empty".to_string(),
 16→        });
 17→    }
 18→    if content.len() > MAX_CONTENT_LENGTH {
 19→        return Err(CoreError::ToolExecution {
 20→            tool_name: tool_name.to_string(),
 21→            message: format!(
 22→                "content exceeds maximum length of {MAX_CONTENT_LENGTH} characters ({} given)",
 23→                content.len()
 24→            ),
 25→        });
 26→    }
 27→    Ok(())
 28→}
 29→
 30→fn get_required_str<'a>(
 31→    input: &'a Value,
 32→    key: &str,
 33→    tool_name: &str,
 34→) -> Result<&'a str, CoreError> {
 35→    input
 36→        .get(key)
 37→        .and_then(Value::as_str)
 38→        .ok_or_else(|| CoreError::ToolExecution {
 39→            tool_name: tool_name.to_string(),
 40→            message: format!("missing required parameter: {key}"),
 41→        })
 42→}
 43→
 44→fn get_required_u64(input: &Value, key: &str, tool_name: &str) -> Result<u64, CoreError> {
 45→    input
 46→        .get(key)
 47→        .and_then(Value::as_u64)
 48→        .ok_or_else(|| CoreError::ToolExecution {
 49→            tool_name: tool_name.to_string(),
 50→            message: format!("missing required parameter: {key}"),
 51→        })
 52→}
