 54→// ── SpacesSendMessageTool ──
 55→
 56→pub struct SpacesSendMessageTool {
 57→    port: Arc<dyn SpacesPort>,
 58→}
 59→
 60→impl SpacesSendMessageTool {
 61→    pub fn new(port: Arc<dyn SpacesPort>) -> Self {
 62→        Self { port }
 63→    }
 64→}
 65→
 66→impl Tool for SpacesSendMessageTool {
 67→    fn definition(&self) -> ToolDefinition {
 68→        ToolDefinition {
 69→            name: "spaces_send_message".to_string(),
 70→            description: "Send a message to a Spaces channel".to_string(),
 71→            input_schema: json!({
 72→                "type": "object",
 73→                "properties": {
 74→                    "channel_id": { "type": "integer", "description": "Target channel ID" },
 75→                    "content": { "type": "string", "description": "Message content (max 4000 chars)", "maxLength": MAX_CONTENT_LENGTH },
 76→                    "thread_id": { "type": "integer", "description": "Optional thread ID to reply in" },
 77→                    "reply_to_id": { "type": "integer", "description": "Optional message ID to reply to" }
 78→                },
 79→                "required": ["channel_id", "content"]
 80→            }),
 81→            title: None,
 82→            output_schema: None,
 83→            annotations: Some(ToolAnnotations {
 84→                read_only: false,
 85→                destructive: false,
 86→                idempotent: false,
 87→                open_world: true,
 88→                requires_confirmation: false,
 89→            }),
 90→            category: Some("spaces".to_string()),
 91→            tags: vec!["spaces".to_string(), "messaging".to_string()],
 92→            timeout_secs: None,
 93→        }
 94→    }
 95→
 96→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
 97→        let channel_id = get_required_u64(&call.input, "channel_id", &call.tool_name)?;
 98→        let content = get_required_str(&call.input, "content", &call.tool_name)?;
 99→        validate_content(content, &call.tool_name)?;
100→
101→        let thread_id = call.input.get("thread_id").and_then(Value::as_u64);
102→        let reply_to_id = call.input.get("reply_to_id").and_then(Value::as_u64);
103→
104→        let msg = self
105→            .port
106→            .send_message(channel_id, content, thread_id, reply_to_id)
107→            .map_err(|e| e.into_core_error(&call.tool_name))?;
108→
109→        Ok(ToolResult {
110→            call_id: call.call_id.clone(),
111→            tool_name: call.tool_name.clone(),
112→            output: serde_json::to_value(&msg).unwrap_or(json!({"status": "sent"})),
113→            content: None,
114→            is_error: false,
115→            state_patch: None,
116→        })
117→    }
118→}
