193→impl Tool for SpacesReadMessagesTool {
194→    fn definition(&self) -> ToolDefinition {
195→        ToolDefinition {
196→            name: "spaces_read_messages".to_string(),
197→            description: "Read messages from a Spaces channel".to_string(),
198→            input_schema: json!({
199→                "type": "object",
200→                "properties": {
201→                    "channel_id": { "type": "integer", "description": "Channel to read from" },
202→                    "limit": { "type": "integer", "description": "Max messages to return (default 50, max 200)", "default": 50, "maximum": 200 },
203→                    "before_id": { "type": "integer", "description": "Only return messages before this ID (pagination)" }
204→                },
205→                "required": ["channel_id"]
206→            }),
207→            title: None,
208→            output_schema: None,
209→            annotations: Some(ToolAnnotations {
210→                read_only: true,
211→                destructive: false,
212→                idempotent: true,
213→                open_world: true,
214→                requires_confirmation: false,
215→            }),
216→            category: Some("spaces".to_string()),
217→            tags: vec!["spaces".to_string(), "messaging".to_string()],
218→            timeout_secs: None,
219→        }
220→    }
221→
222→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
223→        let channel_id = get_required_u64(&call.input, "channel_id", &call.tool_name)?;
224→        let limit = call
225→            .input
226→            .get("limit")
227→            .and_then(Value::as_u64)
228→            .unwrap_or(50)
229→            .min(200) as u32;
230→        let before_id = call.input.get("before_id").and_then(Value::as_u64);
231→
232→        let messages = self
233→            .port
234→            .read_messages(channel_id, limit, before_id)
235→            .map_err(|e| e.into_core_error(&call.tool_name))?;
236→
237→        Ok(ToolResult {
238→            call_id: call.call_id.clone(),
239→            tool_name: call.tool_name.clone(),
240→            output: serde_json::to_value(&messages).unwrap_or(json!([])),
241→            content: None,
242→            is_error: false,
243→            state_patch: None,
244→        })
245→    }
246→}
