250→pub struct SpacesSendDmTool {
251→    port: Arc<dyn SpacesPort>,
252→}
253→
254→impl SpacesSendDmTool {
255→    pub fn new(port: Arc<dyn SpacesPort>) -> Self {
256→        Self { port }
257→    }
258→}
259→
260→impl Tool for SpacesSendDmTool {
261→    fn definition(&self) -> ToolDefinition {
262→        ToolDefinition {
263→            name: "spaces_send_dm".to_string(),
264→            description: "Send a direct message to another agent or user in Spaces".to_string(),
265→            input_schema: json!({
266→                "type": "object",
267→                "properties": {
268→                    "recipient": { "type": "string", "description": "Recipient identity (hex string)" },
269→                    "content": { "type": "string", "description": "Message content (max 4000 chars)", "maxLength": MAX_CONTENT_LENGTH }
270→                },
271→                "required": ["recipient", "content"]
272→            }),
273→            title: None,
274→            output_schema: None,
275→            annotations: Some(ToolAnnotations {
276→                read_only: false,
277→                destructive: false,
278→                idempotent: false,
279→                open_world: true,
280→                requires_confirmation: false,
281→            }),
282→            category: Some("spaces".to_string()),
283→            tags: vec!["spaces".to_string(), "messaging".to_string()],
284→            timeout_secs: None,
285→        }
286→    }
287→
288→    fn execute(&self, call: &ToolCall, _ctx: &ToolContext) -> Result<ToolResult, CoreError> {
289→        let recipient = get_required_str(&call.input, "recipient", &call.tool_name)?;
290→        if recipient.is_empty() {
291→            return Err(CoreError::ToolExecution {
292→                tool_name: call.tool_name.clone(),
293→                message: "recipient must not be empty".to_string(),
294→            });
295→        }
296→
297→        let content = get_required_str(&call.input, "content", &call.tool_name)?;
298→        validate_content(content, &call.tool_name)?;
299→
300→        let dm = self
301→            .port
302→            .send_dm(recipient, content)
303→            .map_err(|e| e.into_core_error(&call.tool_name))?;
304→
305→        Ok(ToolResult {
306→            call_id: call.call_id.clone(),
307→            tool_name: call.tool_name.clone(),
308→            output: serde_json::to_value(&dm).unwrap_or(json!({"status": "sent"})),
309→            content: None,
310→            is_error: false,
311→            state_patch: None,
312→        })
313→    }
314→}
