  1→use crate::error::SpacesBridgeError;
  2→use crate::port::{
  3→    SpacesChannel, SpacesChannelType, SpacesDirectMessage, SpacesMessage, SpacesMessageType,
  4→    SpacesPort,
  5→};
  6→use std::sync::Mutex;
  7→use std::sync::atomic::{AtomicU64, Ordering};
  8→
  9→/// Mock implementation of [`SpacesPort`] for testing.
 10→///
 11→/// Uses interior mutability to record sent messages and DMs.
 12→/// Deterministic IDs via atomic counter.
 13→pub struct MockSpacesClient {
 14→    channels: Mutex<Vec<SpacesChannel>>,
 15→    messages: Mutex<Vec<SpacesMessage>>,
 16→    dms: Mutex<Vec<SpacesDirectMessage>>,
 17→    next_id: AtomicU64,
 18→    /// Set to `Some(error_message)` to force all operations to fail.
 19→    pub force_error: Mutex<Option<String>>,
 20→}
 21→
 22→impl MockSpacesClient {
 23→    /// Create a mock with pre-seeded channels (general, agent-logs, system).
 24→    pub fn default_hub() -> Self {
 25→        let channels = vec![
 26→            SpacesChannel {
 27→                id: 1,
 28→                server_id: 1,
 29→                name: "general".to_string(),
 30→                channel_type: SpacesChannelType::Text,
 31→                description: Some("General discussion".to_string()),
 32→            },
 33→            SpacesChannel {
 34→                id: 2,
 35→                server_id: 1,
 36→                name: "agent-logs".to_string(),
 37→                channel_type: SpacesChannelType::AgentLog,
 38→                description: Some("Agent activity logs".to_string()),
 39→            },
 40→            SpacesChannel {
 41→                id: 3,
 42→                server_id: 1,
 43→                name: "system".to_string(),
 44→                channel_type: SpacesChannelType::Announcement,
 45→                description: Some("System announcements".to_string()),
 46→            },
 47→        ];
 48→
 49→        Self {
 50→            channels: Mutex::new(channels),
 51→            messages: Mutex::new(Vec::new()),
 52→            dms: Mutex::new(Vec::new()),
 53→            next_id: AtomicU64::new(100),
 54→            force_error: Mutex::new(None),
 55→        }
 56→    }
 57→
 58→    fn next_id(&self) -> u64 {
 59→        self.next_id.fetch_add(1, Ordering::Relaxed)
 60→    }
 61→
 62→    fn check_error(&self) -> Result<(), SpacesBridgeError> {
 63→        let guard = self.force_error.lock().expect("force_error lock poisoned");
 64→        if let Some(msg) = guard.as_ref() {
 65→            return Err(SpacesBridgeError::Connection(msg.clone()));
 66→        }
 67→        Ok(())
 68→    }
 69→
 70→    /// Return all messages sent through this mock.
 71→    pub fn sent_messages(&self) -> Vec<SpacesMessage> {
 72→        self.messages
 73→            .lock()
 74→            .expect("messages lock poisoned")
 75→            .clone()
 76→    }
 77→
 78→    /// Return all DMs sent through this mock.
 79→    pub fn sent_dms(&self) -> Vec<SpacesDirectMessage> {
 80→        self.dms.lock().expect("dms lock poisoned").clone()
 81→    }
 82→
 83→    /// Number of messages sent.
 84→    pub fn message_count(&self) -> usize {
 85→        self.messages.lock().expect("messages lock poisoned").len()
 86→    }
 87→
 88→    /// Number of DMs sent.
 89→    pub fn dm_count(&self) -> usize {
 90→        self.dms.lock().expect("dms lock poisoned").len()
 91→    }
 92→}
 93→
 94→impl SpacesPort for MockSpacesClient {
 95→    fn send_message(
 96→        &self,
 97→        channel_id: u64,
 98→        content: &str,
 99→        thread_id: Option<u64>,
100→        reply_to_id: Option<u64>,
101→    ) -> Result<SpacesMessage, SpacesBridgeError> {
102→        self.check_error()?;
103→
104→        let channels = self.channels.lock().expect("channels lock poisoned");
105→        if !channels.iter().any(|c| c.id == channel_id) {
106→            return Err(SpacesBridgeError::ChannelNotFound(format!(
107→                "channel {channel_id}"
108→            )));
109→        }
110→        drop(channels);
111→
112→        let msg = SpacesMessage {
113→            id: self.next_id(),
114→            channel_id,
115→            sender: "mock-agent".to_string(),
116→            content: content.to_string(),
117→            message_type: SpacesMessageType::Text,
118→            created_at: 1_700_000_000_000_000,
119→            thread_id,
120→            reply_to_id,
121→        };
122→
123→        self.messages
124→            .lock()
125→            .expect("messages lock poisoned")
126→            .push(msg.clone());
127→        Ok(msg)
128→    }
129→
130→    fn list_channels(&self, server_id: u64) -> Result<Vec<SpacesChannel>, SpacesBridgeError> {
131→        self.check_error()?;
132→
133→        let channels = self.channels.lock().expect("channels lock poisoned");
134→        let filtered: Vec<SpacesChannel> = channels
135→            .iter()
136→            .filter(|c| c.server_id == server_id)
137→            .cloned()
138→            .collect();
139→        Ok(filtered)
140→    }
141→
142→    fn read_messages(
143→        &self,
144→        channel_id: u64,
145→        limit: u32,
146→        before_id: Option<u64>,
147→    ) -> Result<Vec<SpacesMessage>, SpacesBridgeError> {
148→        self.check_error()?;
149→
150→        let messages = self.messages.lock().expect("messages lock poisoned");
151→        let filtered: Vec<SpacesMessage> = messages
152→            .iter()
153→            .filter(|m| m.channel_id == channel_id)
154→            .filter(|m| match before_id {
155→                Some(bid) => m.id < bid,
156→                None => true,
157→            })
158→            .take(limit as usize)
159→            .cloned()
160→            .collect();
161→        Ok(filtered)
162→    }
163→
164→    fn send_dm(
165→        &self,
166→        recipient: &str,
167→        content: &str,
168→    ) -> Result<SpacesDirectMessage, SpacesBridgeError> {
169→        self.check_error()?;
170→
171→        let dm = SpacesDirectMessage {
172→            id: self.next_id(),
173→            sender: "mock-agent".to_string(),
174→            recipient: recipient.to_string(),
175→            content: content.to_string(),
176→            created_at: 1_700_000_000_000_000,
177→        };
178→
179→        self.dms.lock().expect("dms lock poisoned").push(dm.clone());
180→        Ok(dm)
181→    }
182→}
