 271→async fn shutdown_signal() {
 272→    let ctrl_c = tokio::signal::ctrl_c();
 273→
 274→    #[cfg(unix)]
 275→    {
 276→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
 277→            .expect("failed to install SIGTERM handler");
 278→        tokio::select! {
 279→            _ = ctrl_c => {},
 280→            _ = sigterm.recv() => {},
 281→        }
 282→    }
 283→
 284→    #[cfg(not(unix))]
 285→    {
 286→        ctrl_c.await.ok();
 287→    }
 288→
 289→    tracing::info!("Received shutdown signal, draining connections...");
 290→}
