 318→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
 319→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
 320→async fn resolve_session(
 321→    data_dir: &Path,
 322→    requested: Option<String>,
 323→    base_url: Option<&str>,
 324→) -> String {
 325→    if let Some(session) = requested {
 326→        return session;
 327→    }
 328→
 329→    if let Some(session) = read_last_session_hint(data_dir) {
 330→        return session;
 331→    }
 332→
 333→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
 334→    if let Some(url) = base_url {
 335→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
 336→            return session;
 337→        }
 338→    }
 339→
 340→    "default".to_owned()
 341→}
