 422→fn run_serve(
 423→    data_dir: &Path,
 424→    resolved: &ResolvedConfig,
 425→    console_dir: Option<PathBuf>,
 426→) -> anyhow::Result<()> {
 427→    let workspace_root = std::env::current_dir()?;
 428→
 429→    // --- Lago persistence ---
 430→    let journal_path = data_dir.join("journal.redb");
 431→    let blobs_path = data_dir.join("blobs");
 432→    std::fs::create_dir_all(&blobs_path)?;
 433→
 434→    tracing::info!(
 435→        workspace = %workspace_root.display(),
 436→        journal = %journal_path.display(),
 437→        blobs = %blobs_path.display(),
 438→        provider = %resolved.provider,
 439→        model = ?resolved.model,
 440→        port = resolved.port,
 441→        "Starting arcan"
 442→    );
 443→
 444→    let journal = RedbJournal::open(&journal_path)?;
 445→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 446→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 447→
 448→    // --- Policies ---
 449→    let fs_policy = FsPolicy::new(workspace_root.clone());
 450→    let sandbox_policy = SandboxPolicy {
 451→        workspace_root: workspace_root.clone(),
 452→        shell_enabled: true,
 453→        network: NetworkPolicy::AllowAll,
 454→        allowed_env: BTreeSet::new(),
 455→        max_execution_ms: 10_000,
 456→        max_stdout_bytes: 1024 * 1024,
 457→        max_stderr_bytes: 1024 * 1024,
 458→    };
 459→
 460→    // --- Tools (Praxis canonical implementations, bridged into Arcan) ---
 461→    let mut registry = ToolRegistry::default();
 462→    registry.register(PraxisToolBridge::new(ReadFileTool::new(fs_policy.clone())));
 463→    registry.register(PraxisToolBridge::new(WriteFileTool::new(fs_policy.clone())));
 464→    registry.register(PraxisToolBridge::new(ListDirTool::new(fs_policy.clone())));
 465→    registry.register(PraxisToolBridge::new(EditFileTool::new(fs_policy.clone())));
 466→    registry.register(PraxisToolBridge::new(GlobTool::new(fs_policy.clone())));
 467→    registry.register(PraxisToolBridge::new(GrepTool::new(fs_policy)));
 468→
 469→    let runner = Box::new(LocalCommandRunner);
 470→    registry.register(PraxisToolBridge::new(BashTool::new(sandbox_policy, runner)));
 471→
 472→    let memory_dir = data_dir.join("memory");
 473→    std::fs::create_dir_all(&memory_dir)?;
 474→    registry.register(PraxisToolBridge::new(ReadMemoryTool::new(
 475→        memory_dir.clone(),
 476→    )));
 477→    registry.register(PraxisToolBridge::new(WriteMemoryTool::new(memory_dir)));
 478→
 479→    // --- Governed memory tools (event-sourced via Lago) ---
 480→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 481→    registry.register(MemoryQueryTool::new(memory_projection));
 482→    registry.register(MemoryProposeTool::new(journal.clone()));
 483→    registry.register(MemoryCommitTool::new(journal.clone()));
 484→
 485→    // --- Spaces distributed networking (opt-in) ---
 486→    #[cfg(feature = "spaces")]
 487→    {
 488→        let spaces_port: Arc<dyn arcan_spaces::SpacesPort> =
 489→            Arc::new(arcan_spaces::MockSpacesClient::default_hub());
 490→        arcan_spaces::register_spaces_tools(&mut registry, spaces_port);
 491→    }
 492→
 493→    // --- Provider ---
 494→    let provider = build_provider(resolved)?;
 495→
 496→    // Swappable handle for live provider switching
 497→    let provider_handle: arcan_core::runtime::SwappableProviderHandle =
 498→        Arc::new(std::sync::RwLock::new(provider));
 499→    let provider_factory: Arc<dyn arcan_core::runtime::ProviderFactory> =
 500→        Arc::new(factory::ArcanProviderFactory);
 501→
 502→    // --- Canonical aiOS runtime adapters ---
 503→    let event_store: Arc<dyn EventStorePort> =
 504→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 505→    // Shared handle: starts empty, filled after runtime creation.
 506→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 507→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::from_handle(
 508→        provider_handle.clone(),
 509→        registry.definitions(),
 510→        streaming_sender.clone(),
 511→    ));
 512→    let observer = Arc::new(LakeFsObserver {
 513→        workspace_root: workspace_root.clone(),
 514→        journal: journal.clone(),
 515→        blob_store: _blob_store,
 516→    });
 517→    let tool_harness: Arc<dyn ToolHarnessPort> =
 518→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
 519→    let base_policy: Arc<dyn PolicyGatePort> =
 520→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 521→
 522→    let (policy_gate, _economic_handle): (Arc<dyn PolicyGatePort>, Option<EconomicGateHandle>) =
 523→        if let Some(url) = &resolved.autonomic_url {
 524→            tracing::info!(url = %url, "Autonomic advisory enabled");
 525→            let adapter = AutonomicPolicyAdapter::new(base_policy, url.clone());
 526→            let handle = adapter.economic_handle();
 527→            (Arc::new(adapter), Some(handle))
 528→        } else {
 529→            (base_policy, None)
 530→        };
 531→
 532→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 533→
 534→    let runtime = Arc::new(KernelRuntime::new(
 535→        RuntimeConfig::new(data_dir.to_path_buf()),
 536→        event_store,
 537→        provider_adapter,
 538→        tool_harness,
 539→        approvals,
 540→        policy_gate,
 541→    ));
 542→
 543→    // Wire the broadcast sender now that the runtime exists.
 544→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 545→
 546→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 547→    let data_dir_owned = data_dir.to_path_buf();
 548→    let port = resolved.port;
 549→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 550→        .enable_all()
 551→        .build()?;
 552→
 553→    tokio_runtime.block_on(async move {
 554→        // --- HTTP Server ---
 555→        let mut router = create_canonical_router(runtime, provider_handle, provider_factory);
 556→
 557→        // --- Console UI ---
 558→        #[cfg(feature = "console")]
 559→        {
 560→            let console_config = arcan_console::ConsoleConfig {
 561→                override_dir: console_dir,
 562→            };
 563→            router = router.nest("/console", arcan_console::console_router(console_config));
 564→        }
 565→
 566→        // --- CORS (for dev mode with separate Vite server) ---
 567→        let cors = tower_http::cors::CorsLayer::permissive();
 568→        let router = router.layer(cors);
 569→
 570→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 571→        let listener = TcpListener::bind(addr).await?;
 572→
 573→        tracing::info!(%addr, "Listening");
 574→        axum::serve(listener, router)
 575→            .with_graceful_shutdown(shutdown_signal())
 576→            .await?;
 577→
 578→        // Clean up PID file on graceful shutdown.
 579→        daemon::remove_pid_file(&data_dir_owned);
 580→
 581→        tracing::info!("Server shut down gracefully");
 582→        Ok(())
 583→    })
 584→}
