 713→#[allow(clippy::print_stdout)]
 714→async fn run_status(data_dir: &Path, resolved: &ResolvedConfig) -> anyhow::Result<()> {
 715→    println!("Arcan Status");
 716→    println!("============");
 717→
 718→    // Config
 719→    println!(
 720→        "Provider:   {}",
 721→        if resolved.provider.is_empty() {
 722→            "(auto-detect)"
 723→        } else {
 724→            &resolved.provider
 725→        }
 726→    );
 727→    println!(
 728→        "Model:      {}",
 729→        resolved.model.as_deref().unwrap_or("(provider default)")
 730→    );
 731→    println!("Port:       {}", resolved.port);
 732→    println!("Data dir:   {}", data_dir.display());
 733→
 734→    // Daemon status
 735→    let base_url = format!("http://127.0.0.1:{}", resolved.port);
 736→    match daemon::check_existing_pid(data_dir) {
 737→        Some(pid) => {
 738→            let client = reqwest::Client::builder()
 739→                .timeout(std::time::Duration::from_secs(2))
 740→                .build()?;
 741→            let healthy = matches!(
 742→                client.get(format!("{base_url}/health")).send().await,
 743→                Ok(resp) if resp.status().is_success()
 744→            );
 745→            if healthy {
 746→                println!("Daemon:     running (PID {pid}, healthy)");
 747→            } else {
 748→                println!("Daemon:     running (PID {pid}, NOT healthy)");
 749→            }
 750→        }
 751→        None => {
 752→            println!("Daemon:     not running");
 753→        }
 754→    }
 755→
 756→    // Last session
 757→    match read_last_session_hint(data_dir) {
 758→        Some(session) => println!("Session:    {session}"),
 759→        None => println!("Session:    (none)"),
 760→    }
 761→
 762→    // Config file locations
 763→    if let Some(global_path) = config::global_config_path() {
 764→        let exists = global_path.exists();
 765→        println!(
 766→            "Global cfg: {} {}",
 767→            global_path.display(),
 768→            if exists { "" } else { "(not found)" }
 769→        );
 770→    }
 771→    let local_path = config::local_config_path(data_dir);
 772→    let exists = local_path.exists();
 773→    println!(
 774→        "Local cfg:  {} {}",
 775→        local_path.display(),
 776→        if exists { "" } else { "(not found)" }
 777→    );
 778→
 779→    Ok(())
 780→}
