 814→#[allow(clippy::print_stdout)]
 815→async fn run_api(
 816→    data_dir: PathBuf,
 817→    resolved: &ResolvedConfig,
 818→    url: Option<String>,
 819→    output: Option<PathBuf>,
 820→) -> anyhow::Result<()> {
 821→    // If --output is given, write the spec to a file and exit.
 822→    if let Some(path) = output {
 823→        let spec = arcand::canonical::openapi_spec();
 824→        let json = serde_json::to_string_pretty(&spec)?;
 825→        std::fs::write(&path, &json)?;
 826→        println!("OpenAPI spec written to {}", path.display());
 827→        return Ok(());
 828→    }
 829→
 830→    // Ensure daemon is running.
 831→    let base_url = match url {
 832→        Some(u) => u,
 833→        None => {
 834→            daemon::ensure_daemon(
 835→                &data_dir,
 836→                resolved.port,
 837→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 838→                resolved.model.as_deref(),
 839→            )
 840→            .await?
 841→        }
 842→    };
 843→
 844→    let docs_url = format!("{base_url}/docs");
 845→    println!("API docs available at: {docs_url}");
 846→
 847→    // Try to open the browser.
 848→    let opened = std::process::Command::new("open")
 849→        .arg(&docs_url)
 850→        .stdout(std::process::Stdio::null())
 851→        .stderr(std::process::Stdio::null())
 852→        .status()
 853→        .is_ok_and(|s| s.success());
 854→
 855→    if !opened {
 856→        println!("Open the URL above in your browser to explore the API.");
 857→    }
 858→
 859→    println!();
 860→    println!("Raw spec: {base_url}/openapi.json");
 861→
 862→    Ok(())
 863→}
