 886→fn main() -> anyhow::Result<()> {
 887→    let cli = Cli::parse();
 888→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 889→
 890→    // Load layered config.
 891→    let file_config = config::load_config(&data_dir);
 892→
 893→    match cli.command {
 894→        Some(Command::Serve {
 895→            max_iterations,
 896→            approval_timeout,
 897→        }) => {
 898→            // Structured logging to stderr for daemon mode
 899→            tracing_subscriber::fmt()
 900→                .with_env_filter(EnvFilter::from_default_env())
 901→                .init();
 902→
 903→            let resolved = config::resolve(
 904→                &file_config,
 905→                cli.provider.as_deref(),
 906→                cli.model.as_deref(),
