 910→                cli.autonomic_url.as_deref(),
 911→            );
 912→
 913→            run_serve(&data_dir, &resolved, cli.console_dir)
 914→        }
 915→        Some(Command::Chat { session, url }) => {
 916→            // File-based logging for TUI mode (don't clobber the terminal)
 917→            let log_dir = data_dir.join("logs");
 918→            std::fs::create_dir_all(&log_dir)?;
 919→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 920→            tracing_subscriber::fmt()
 921→                .with_writer(file_appender)
 922→                .with_env_filter(EnvFilter::from_default_env())
 923→                .init();
 924→
 925→            let resolved = config::resolve(
 926→                &file_config,
 927→                cli.provider.as_deref(),
