 967→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
 968→            tracing_subscriber::fmt()
 969→                .with_writer(file_appender)
 970→                .with_env_filter(EnvFilter::from_default_env())
 971→                .init();
 972→
 973→            let resolved = config::resolve(
