 11→pub fn validate_username(s: &str) -> Result<(), String> {
 12→    if s.is_empty() {
 13→        return Err("Username cannot be empty".to_string());
 14→    }
 15→    if s.len() > 32 {
 16→        return Err("Username must be 32 characters or fewer".to_string());
 17→    }
 18→    Ok(())
 19→}
