 70→// ---------------------------------------------------------------------------
 71→// Role hierarchy
 72→// ---------------------------------------------------------------------------
 73→
 74→pub const ROLE_LEVEL_OWNER: u8 = 4;
 75→pub const ROLE_LEVEL_ADMIN: u8 = 3;
 76→pub const ROLE_LEVEL_MODERATOR: u8 = 2;
 77→pub const ROLE_LEVEL_MEMBER: u8 = 1;
 78→pub const ROLE_LEVEL_AGENT: u8 = 1;
 79→
 80→/// Check whether `actor` can change `target`'s role to `new_role`.
 81→///
 82→/// Rules:
 83→/// - Cannot change the owner's role
 84→/// - Cannot assign the Owner role
 85→/// - Actor must outrank the target's current role
 86→/// - Actor must outrank the new role
 87→pub fn can_modify_role(
 88→    actor_level: u8,
 89→    target_level: u8,
 90→    new_role_level: u8,
 91→    target_is_owner: bool,
 92→    new_role_is_owner: bool,
 93→) -> Result<(), String> {
 94→    if target_is_owner {
 95→        return Err("Cannot change the owner's role".to_string());
 96→    }
 97→    if new_role_is_owner {
 98→        return Err("Cannot assign Owner role. Use transfer ownership instead.".to_string());
 99→    }
100→    if actor_level <= target_level {
101→        return Err("Cannot modify role of someone with equal or higher rank".to_string());
102→    }
103→    if actor_level <= new_role_level {
104→        return Err("Cannot assign a role equal to or higher than your own".to_string());
105→    }
106→    Ok(())
107→}
