  30→/// Hook trait for approval gates, allowing the agent loop to wire event handlers
  31→/// into the gate without depending on the concrete `ApprovalGate` type.
  32→pub trait ApprovalGateHook: Send + Sync {
  33→    fn set_event_handler(&self, handler: Arc<dyn Fn(AgentEvent) + Send + Sync>);
  34→    fn clear_event_handler(&self);
  35→}
