  37→/// Trait for resolving pending approvals from HTTP endpoints.
  38→pub trait ApprovalResolver: Send + Sync {
  39→    fn resolve_approval(&self, approval_id: &str, decision: &str, reason: Option<String>) -> bool;
  40→    fn pending_approval_ids(&self) -> Vec<String>;
  41→}
