  60→    }
  61→
  62→    /// Stream a completion, calling `on_text` for each text delta as it arrives.
  63→    /// Returns the final assembled `ModelTurn`. Default falls back to `complete()`.
  64→    fn complete_streaming(
  65→        &self,
  66→        request: &ProviderRequest,
  67→        _on_text: &dyn Fn(&str),
  68→    ) -> Result<ModelTurn, CoreError> {
  69→        self.complete(request)
  70→    }
