 11→#[reducer]
 12→pub fn create_server(
 13→    ctx: &ReducerContext,
 14→    name: String,
 15→    description: Option<String>,
 16→) -> Result<(), String> {
 17→    validation::validate_name(&name, "Server")?;
 18→
 19→    // Ensure user has a profile
 20→    ctx.db
 21→        .user_profile()
 22→        .identity()
 23→        .find(ctx.sender())
 24→        .ok_or("Must be connected to create a server")?;
 25→
 26→    let server = ctx.db.server().insert(Server {
 27→        id: 0,
 28→        name,
 29→        description,
 30→        icon_url: None,
 31→        owner: ctx.sender(),
 32→        created_at: ctx.timestamp,
 33→    });
 34→
 35→    // Add owner as member
 36→    ctx.db.server_member().insert(ServerMember {
 37→        id: 0,
 38→        server_id: server.id,
 39→        identity: ctx.sender(),
 40→        role: MemberRole::Owner,
 41→        joined_at: ctx.timestamp,
 42→    });
 43→
 44→    // Create default #general channel
 45→    ctx.db.channel().insert(Channel {
 46→        id: 0,
 47→        server_id: server.id,
 48→        name: "general".to_string(),
 49→        topic: Some("General discussion".to_string()),
 50→        channel_type: ChannelType::Text,
 51→        position: 0,
 52→        created_at: ctx.timestamp,
 53→    });
 54→
 55→    log::info!(
 56→        "Server '{}' (id={}) created by {:?}",
 57→        server.name,
 58→        server.id,
 59→        ctx.sender()
 60→    );
 61→    Ok(())
 62→}
