 64→#[reducer]
 65→pub fn update_server(
 66→    ctx: &ReducerContext,
 67→    server_id: u64,
 68→    name: Option<String>,
 69→    description: Option<String>,
 70→) -> Result<(), String> {
 71→    auth::require_role(ctx, server_id, MemberRole::Admin)?;
 72→
 73→    let server = ctx
 74→        .db
 75→        .server()
 76→        .id()
 77→        .find(server_id)
 78→        .ok_or("Server not found")?;
 79→
 80→    let new_name = name.unwrap_or(server.name.clone());
 81→    validation::validate_name(&new_name, "Server")?;
 82→
 83→    ctx.db.server().id().update(Server {
 84→        name: new_name,
 85→        description: description.or(server.description.clone()),
 86→        ..server
 87→    });
 88→
 89→    Ok(())
 90→}
