 92→#[reducer]
 93→pub fn delete_server(ctx: &ReducerContext, server_id: u64) -> Result<(), String> {
 94→    let server = ctx
 95→        .db
 96→        .server()
 97→        .id()
 98→        .find(server_id)
 99→        .ok_or("Server not found")?;
100→
101→    validation::guard_only_owner_deletes(server.owner == ctx.sender())?;
102→
103→    // Cascade delete: messages, channels, members
104→    let channels: Vec<_> = ctx.db.channel().server_id().filter(&server_id).collect();
105→    for ch in &channels {
106→        let messages: Vec<_> = ctx.db.message().channel_id().filter(&ch.id).collect();
107→        for msg in &messages {
108→            // Delete reactions for this message
109→            let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&msg.id).collect();
110→            for r in &reactions {
111→                ctx.db.reaction().id().delete(r.id);
112→            }
113→            ctx.db.message().id().delete(msg.id);
114→        }
115→        // Delete threads
116→        let threads: Vec<_> = ctx.db.thread().channel_id().filter(&ch.id).collect();
117→        for t in &threads {
118→            ctx.db.thread().id().delete(t.id);
119→        }
120→        ctx.db.channel().id().delete(ch.id);
121→    }
122→
123→    // Delete members
124→    let members: Vec<_> = ctx
125→        .db
126→        .server_member()
127→        .server_id()
128→        .filter(&server_id)
129→        .collect();
130→    for m in &members {
131→        ctx.db.server_member().id().delete(m.id);
132→    }
133→
134→    ctx.db.server().id().delete(server_id);
135→    log::info!("Server {} deleted by {:?}", server_id, ctx.sender());
136→    Ok(())
137→}
