139→#[reducer]
140→pub fn join_server(ctx: &ReducerContext, server_id: u64) -> Result<(), String> {
141→    ctx.db
142→        .server()
143→        .id()
144→        .find(server_id)
145→        .ok_or("Server not found")?;
146→
147→    ctx.db
148→        .user_profile()
149→        .identity()
150→        .find(ctx.sender())
151→        .ok_or("Must be connected to join a server")?;
152→
153→    // Check not already a member
154→    if auth::get_membership(ctx, server_id, ctx.sender()).is_some() {
155→        return Err("Already a member of this server".to_string());
156→    }
157→
158→    let is_agent = ctx
159→        .db
160→        .user_profile()
161→        .identity()
162→        .find(ctx.sender())
163→        .map(|p| p.is_agent)
164→        .unwrap_or(false);
165→
166→    let role = if is_agent {
167→        MemberRole::Agent
168→    } else {
169→        MemberRole::Member
170→    };
171→
172→    ctx.db.server_member().insert(ServerMember {
173→        id: 0,
