 11→#[reducer]
 12→pub fn send_message(
 13→    ctx: &ReducerContext,
 14→    channel_id: u64,
 15→    content: String,
 16→    thread_id: Option<u64>,
 17→    reply_to_id: Option<u64>,
 18→) -> Result<(), String> {
 19→    validation::validate_message_content(&content)?;
 20→
 21→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
 22→    auth::require_member(ctx, channel.server_id)?;
 23→
 24→    // Validate thread exists if specified
 25→    if let Some(tid) = thread_id {
 26→        let thread = ctx.db.thread().id().find(tid).ok_or("Thread not found")?;
 27→        validation::guard_thread_not_archived(thread.archived)?;
 28→        validation::guard_thread_channel(thread.channel_id, channel_id)?;
 29→        // Update thread's last_message_at
 30→        ctx.db.thread().id().update(Thread {
 31→            last_message_at: ctx.timestamp,
 32→            ..thread
 33→        });
 34→    }
 35→
 36→    // Validate reply target exists if specified
 37→    if let Some(rid) = reply_to_id {
 38→        ctx.db
 39→            .message()
 40→            .id()
 41→            .find(rid)
 42→            .ok_or("Reply target message not found")?;
 43→    }
 44→
 45→    ctx.db.message().insert(Message {
 46→        id: 0,
 47→        channel_id,
 48→        thread_id,
 49→        sender: ctx.sender(),
 50→        content,
 51→        message_type: MessageType::Text,
 52→        created_at: ctx.timestamp,
 53→        edited_at: None,
 54→        reply_to_id,
 55→    });
 56→
 57→    Ok(())
 58→}
