 86→#[reducer]
 87→pub fn delete_message(ctx: &ReducerContext, message_id: u64) -> Result<(), String> {
 88→    let msg = ctx
 89→        .db
 90→        .message()
 91→        .id()
 92→        .find(message_id)
 93→        .ok_or("Message not found")?;
 94→
 95→    let is_sender = msg.sender == ctx.sender();
 96→
 97→    // Check if admin+ in the server
 98→    let (_channel, _server) = auth::get_server_for_channel(ctx, msg.channel_id)?;
 99→    let is_admin = auth::get_member_role(ctx, _channel.server_id, ctx.sender())
100→        .map(|r| r.level() >= MemberRole::Admin.level())
101→        .unwrap_or(false);
102→
103→    validation::guard_delete_permission(is_sender, is_admin)?;
104→
105→    // Delete reactions first
106→    let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&message_id).collect();
107→    for r in &reactions {
108→        ctx.db.reaction().id().delete(r.id);
109→    }
110→
111→    ctx.db.message().id().delete(message_id);
112→    Ok(())
113→}
