126→    // Verify membership
127→    let (channel, _server) = auth::get_server_for_channel(ctx, msg.channel_id)?;
128→    auth::require_member(ctx, channel.server_id)?;
129→
130→    // Check for duplicate reaction
131→    let already = ctx
132→        .db
133→        .reaction()
134→        .message_id()
135→        .filter(&message_id)
136→        .any(|r| r.identity == ctx.sender() && r.emoji == emoji);
