65→pub fn delete_channel(ctx: &ReducerContext, channel_id: u64) -> Result<(), String> {
66→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
67→    auth::require_role(ctx, channel.server_id, MemberRole::Admin)?;
68→
69→    // Cascade delete messages and reactions
70→    let messages: Vec<_> = ctx.db.message().channel_id().filter(&channel_id).collect();
71→    for msg in &messages {
72→        let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&msg.id).collect();
73→        for r in &reactions {
74→            ctx.db.reaction().id().delete(r.id);
75→        }
76→        ctx.db.message().id().delete(msg.id);
77→    }
78→
79→    // Delete threads
80→    let threads: Vec<_> = ctx.db.thread().channel_id().filter(&channel_id).collect();
81→    for t in &threads {
82→        ctx.db.thread().id().delete(t.id);
83→    }
84→
85→    ctx.db.channel().id().delete(channel_id);
86→    Ok(())
