  1→use spacetimedb::{reducer, Identity, ReducerContext, Table};
  2→
  3→use crate::tables::{
  4→    direct_conversation, direct_message, user_profile, DirectConversation, DirectMessage,
  5→};
  6→use crate::validation;
  7→
  8→/// Normalize two identities so the lexicographically smaller hex comes first.
  9→/// This ensures a unique conversation per pair regardless of who initiates.
 10→fn normalize_participants(a: Identity, b: Identity) -> (Identity, Identity) {
 11→    if a.to_hex().to_string() <= b.to_hex().to_string() {
 12→        (a, b)
 13→    } else {
 14→        (b, a)
 15→    }
 16→}
 17→
 18→/// Find an existing conversation between two participants.
 19→fn find_conversation(ctx: &ReducerContext, a: Identity, b: Identity) -> Option<DirectConversation> {
 20→    let (norm_a, norm_b) = normalize_participants(a, b);
 21→    ctx.db
 22→        .direct_conversation()
 23→        .iter()
 24→        .find(|c| c.participant_a == norm_a && c.participant_b == norm_b)
 25→}
 26→
 27→#[reducer]
 28→pub fn send_direct_message(
 29→    ctx: &ReducerContext,
 30→    recipient: Identity,
 31→    content: String,
 32→) -> Result<(), String> {
 33→    let sender = ctx.sender();
 34→
 35→    validation::validate_dm_not_self(
 36→        &sender.to_hex().to_string(),
 37→        &recipient.to_hex().to_string(),
 38→    )?;
 39→    validation::validate_message_content(&content)?;
 40→
 41→    // Verify both users exist
 42→    ctx.db
 43→        .user_profile()
 44→        .identity()
 45→        .find(sender)
 46→        .ok_or("Sender profile not found. Connect first.")?;
 47→    ctx.db
 48→        .user_profile()
 49→        .identity()
 50→        .find(recipient)
 51→        .ok_or("Recipient not found")?;
 52→
 53→    // Find or create conversation
 54→    let conversation = if let Some(conv) = find_conversation(ctx, sender, recipient) {
 55→        // Update last_message_at
 56→        ctx.db
 57→            .direct_conversation()
 58→            .id()
 59→            .update(DirectConversation {
 60→                last_message_at: ctx.timestamp,
 61→                ..conv
 62→            })
 63→    } else {
 64→        let (norm_a, norm_b) = normalize_participants(sender, recipient);
 65→        ctx.db.direct_conversation().insert(DirectConversation {
 66→            id: 0,
 67→            participant_a: norm_a,
 68→            participant_b: norm_b,
 69→            created_at: ctx.timestamp,
 70→            last_message_at: ctx.timestamp,
 71→        })
 72→    };
 73→
 74→    ctx.db.direct_message().insert(DirectMessage {
 75→        id: 0,
 76→        conversation_id: conversation.id,
 77→        sender,
 78→        content,
 79→        created_at: ctx.timestamp,
 80→        edited_at: None,
 81→        read: false,
 82→    });
 83→
 84→    Ok(())
 85→}
 86→
 87→#[reducer]
 88→pub fn edit_direct_message(
 89→    ctx: &ReducerContext,
 90→    message_id: u64,
 91→    new_content: String,
 92→) -> Result<(), String> {
 93→    validation::validate_message_content(&new_content)?;
 94→
 95→    let msg = ctx
 96→        .db
 97→        .direct_message()
 98→        .id()
 99→        .find(message_id)
100→        .ok_or("Direct message not found")?;
101→
102→    validation::guard_message_owner(msg.sender == ctx.sender())?;
103→
104→    ctx.db.direct_message().id().update(DirectMessage {
105→        content: new_content,
106→        edited_at: Some(ctx.timestamp),
107→        ..msg
108→    });
109→
110→    Ok(())
111→}
112→
113→#[reducer]
114→pub fn delete_direct_message(ctx: &ReducerContext, message_id: u64) -> Result<(), String> {
115→    let msg = ctx
116→        .db
117→        .direct_message()
118→        .id()
119→        .find(message_id)
120→        .ok_or("Direct message not found")?;
121→
122→    validation::guard_message_owner(msg.sender == ctx.sender())?;
123→
124→    ctx.db.direct_message().id().delete(message_id);
125→    Ok(())
126→}
127→
128→#[reducer]
129→pub fn mark_dm_read(ctx: &ReducerContext, conversation_id: u64) -> Result<(), String> {
130→    let conversation = ctx
131→        .db
132→        .direct_conversation()
133→        .id()
134→        .find(conversation_id)
135→        .ok_or("Conversation not found")?;
136→
137→    // Verify the caller is a participant
138→    let sender = ctx.sender();
139→    if conversation.participant_a != sender && conversation.participant_b != sender {
140→        return Err("You are not a participant in this conversation".to_string());
141→    }
142→
143→    // Mark all unread messages from the other participant as read
144→    let messages: Vec<_> = ctx
145→        .db
146→        .direct_message()
147→        .conversation_id()
148→        .filter(&conversation_id)
149→        .filter(|m| m.sender != sender && !m.read)
150→        .collect();
151→
152→    for msg in messages {
153→        ctx.db
154→            .direct_message()
155→            .id()
156→            .update(DirectMessage { read: true, ..msg });
157→    }
158→
159→    Ok(())
160→}
