 13→static READY: AtomicBool = AtomicBool::new(false);
 14→static CURRENT_SERVER_ID: AtomicU64 = AtomicU64::new(0);
 15→static CURRENT_CHANNEL_ID: AtomicU64 = AtomicU64::new(0);
 16→
 17→fn current_server() -> Option<u64> {
 18→    let v = CURRENT_SERVER_ID.load(Ordering::Relaxed);
 19→    if v == 0 { None } else { Some(v) }
 20→}
 21→
 22→fn current_channel() -> Option<u64> {
 23→    let v = CURRENT_CHANNEL_ID.load(Ordering::Relaxed);
 24→    if v == 0 { None } else { Some(v) }
 25→}
