 27→// --- Main ---
 28→
 29→fn main() {
 30→    let ctx = connect_to_db();
 31→    register_callbacks(&ctx);
 32→    subscribe_to_tables(&ctx);
 33→    ctx.run_threaded();
 34→    user_input_loop(&ctx);
