 81→// --- Callbacks ---
 82→
 83→fn register_callbacks(ctx: &DbConnection) {
 84→    ctx.db.user_profile().on_insert(on_user_profile_inserted);
 85→    ctx.db.user_presence().on_update(on_user_presence_updated);
 86→    ctx.db.message().on_insert(on_message_inserted);
 87→    ctx.db.server().on_insert(on_server_inserted);
 88→    ctx.db.channel().on_insert(on_channel_inserted);
 89→    #[cfg(feature = "dm")]
 90→    ctx.db
 91→        .direct_message()
 92→        .on_insert(on_direct_message_inserted);
 93→}
 94→
 95→fn on_user_profile_inserted(ctx: &EventContext, profile: &UserProfile) {
 96→    if matches!(ctx.event, Event::SubscribeApplied) {
 97→        return;
 98→    }
 99→    println!("[+] New user: {}", profile.username);
100→}
101→
102→fn on_user_presence_updated(_ctx: &EventContext, old: &UserPresence, new: &UserPresence) {
103→    let name = _ctx
104→        .db
105→        .user_profile()
106→        .identity()
107→        .find(&new.identity)
108→        .map(|p| p.username.clone())
109→        .unwrap_or_else(|| "unknown".to_string());
110→    if !old.online && new.online {
111→        println!("[+] {} came online", name);
112→    } else if old.online && !new.online {
113→        println!("[-] {} went offline", name);
114→    }
115→}
116→
117→fn on_message_inserted(ctx: &EventContext, msg: &Message) {
118→    if matches!(ctx.event, Event::SubscribeApplied) {
119→        return;
120→    }
121→    // Only show messages for the current channel
122→    if let Some(ch_id) = current_channel()
123→        && msg.channel_id == ch_id
124→    {
125→        print_message(ctx, msg);
126→    }
127→}
128→
129→fn on_server_inserted(ctx: &EventContext, server: &Server) {
130→    if matches!(ctx.event, Event::SubscribeApplied) {
131→        return;
132→    }
133→    println!("[+] New server: {} (id={})", server.name, server.id);
134→}
135→
136→fn on_channel_inserted(ctx: &EventContext, channel: &Channel) {
137→    if matches!(ctx.event, Event::SubscribeApplied) {
138→        return;
139→    }
140→    println!("[+] New channel: #{} (id={})", channel.name, channel.id);
141→}
142→
143→#[cfg(feature = "dm")]
144→fn on_direct_message_inserted(ctx: &EventContext, msg: &DirectMessage) {
145→    if matches!(ctx.event, Event::SubscribeApplied) {
146→        return;
147→    }
148→    let sender_name = user_display_name(ctx, &msg.sender);
149→    println!("[DM] {}: {}", sender_name, msg.content);
150→}
