152→// --- Helpers ---
153→
154→fn user_display_name(ctx: &impl RemoteDbContext, identity: &Identity) -> String {
155→    ctx.db()
156→        .user_profile()
157→        .identity()
158→        .find(identity)
159→        .map(|p| p.display_name.clone().unwrap_or_else(|| p.username.clone()))
160→        .unwrap_or_else(|| identity.to_abbreviated_hex().to_string())
161→}
162→
163→fn print_message(ctx: &impl RemoteDbContext, msg: &Message) {
164→    let sender = user_display_name(ctx, &msg.sender);
165→    let type_prefix = match msg.message_type {
166→        MessageType::System => "[SYSTEM] ",
167→        MessageType::Join => "[JOIN] ",
168→        MessageType::Leave => "[LEAVE] ",
169→        MessageType::AgentEvent => "[AGENT] ",
170→        MessageType::Text => "",
171→    };
172→    let thread_suffix = msg
173→        .thread_id
174→        .map(|t| format!(" (thread:{})", t))
175→        .unwrap_or_default();
176→    let reply_suffix = msg
177→        .reply_to_id
178→        .map(|r| format!(" (reply to:{})", r))
179→        .unwrap_or_default();
180→    let edit_mark = if msg.edited_at.is_some() {
181→        " (edited)"
182→    } else {
183→        ""
184→    };
185→    println!(
186→        "{}{}: {}{}{}{}",
187→        type_prefix, sender, msg.content, thread_suffix, reply_suffix, edit_mark
188→    );
189→}
