191→// --- Subscriptions ---
192→
193→fn subscribe_to_tables(ctx: &DbConnection) {
194→    ctx.subscription_builder()
195→        .on_applied(on_sub_applied)
196→        .on_error(on_sub_error)
197→        .subscribe_to_all_tables();
198→}
199→
200→fn on_sub_applied(ctx: &SubscriptionEventContext) {
201→    println!("\n=== Spaces - Discord Clone on SpacetimeDB ===\n");
202→
203→    // List servers
204→    let servers: Vec<_> = ctx.db.server().iter().collect();
205→    if servers.is_empty() {
206→        println!("No servers found.");
207→    } else {
208→        println!("Servers:");
209→        for s in &servers {
210→            println!("  [{}] {}", s.id, s.name);
211→        }
212→    }
213→
214→    // Auto-select first server
215→    if let Some(first) = servers.first() {
216→        CURRENT_SERVER_ID.store(first.id, Ordering::Relaxed);
217→        println!("\nActive server: {} (id={})", first.name, first.id);
218→
219→        // Show channels
220→        let channels: Vec<_> = ctx
221→            .db
222→            .channel()
223→            .iter()
224→            .filter(|c| c.server_id == first.id)
225→            .collect();
226→        if !channels.is_empty() {
227→            println!("Channels:");
228→            for ch in &channels {
229→                println!("  [{}] #{} ({:?})", ch.id, ch.name, ch.channel_type);
230→            }
231→            // Auto-select first text channel
232→            if let Some(text_ch) = channels
233→                .iter()
234→                .find(|c| c.channel_type == ChannelType::Text)
235→            {
236→                CURRENT_CHANNEL_ID.store(text_ch.id, Ordering::Relaxed);
237→                println!("\nActive channel: #{} (id={})", text_ch.name, text_ch.id);
238→
239→                // Show recent messages
240→                let mut msgs: Vec<_> = ctx
241→                    .db
242→                    .message()
243→                    .iter()
244→                    .filter(|m| m.channel_id == text_ch.id && m.thread_id.is_none())
245→                    .collect();
246→                msgs.sort_by_key(|m| m.created_at);
247→                let recent: Vec<_> = msgs
248→                    .iter()
249→                    .rev()
250→                    .take(25)
251→                    .collect::<Vec<_>>()
252→                    .into_iter()
253→                    .rev()
254→                    .collect();
255→                if !recent.is_empty() {
256→                    println!("\n--- Recent messages ---");
257→                    for msg in recent {
258→                        print_message(ctx, msg);
259→                    }
260→                    println!("--- End ---\n");
261→                }
262→            }
263→        }
264→    }
265→
266→    println!("Type /help for commands, or type a message to send.");
267→    println!();
268→    READY.store(true, Ordering::Release);
269→}
270→
271→fn on_sub_error(_ctx: &ErrorContext, err: Error) {
272→    eprintln!("Subscription failed: {err}");
273→    std::process::exit(1);
274→}
