276→// --- User Input ---
277→
278→fn user_input_loop(ctx: &DbConnection) {
279→    // Wait for subscription to be applied before processing input
280→    while !READY.load(Ordering::Acquire) {
281→        std::thread::sleep(std::time::Duration::from_millis(50));
282→    }
283→    for line in std::io::stdin().lines() {
284→        let Ok(line) = line else {
285→            break;
286→        };
287→        let line = line.trim().to_string();
288→        if line.is_empty() {
289→            continue;
290→        }
291→
292→        if line.starts_with('/') {
293→            handle_command(ctx, &line);
294→        } else {
295→            // Send message to current channel
296→            if let Some(ch_id) = current_channel() {
297→                if let Err(e) = ctx.reducers.send_message(ch_id, line, None, None) {
298→                    eprintln!("Failed to send: {e}");
299→                }
300→            } else {
301→                eprintln!("No channel selected. Use /channel <id> to select one.");
302→            }
303→        }
304→    }
305→}
306→
307→fn handle_command(ctx: &DbConnection, input: &str) {
308→    let parts: Vec<&str> = input.splitn(2, ' ').collect();
309→    let cmd = parts[0];
310→    let arg = parts.get(1).map(|s| s.trim()).unwrap_or("");
311→
312→    match cmd {
313→        "/help" => print_help(),
314→        "/name" => cmd_set_name(ctx, arg),
315→        "/servers" => cmd_list_servers(ctx),
316→        "/server" => cmd_select_server(ctx, arg),
317→        "/join" => cmd_join_server(ctx, arg),
318→        "/leave" => cmd_leave_server(ctx, arg),
319→        "/create-server" => cmd_create_server(ctx, arg),
320→        "/channels" => cmd_list_channels(ctx),
321→        "/channel" => cmd_select_channel(ctx, arg),
322→        "/create-channel" => cmd_create_channel(ctx, arg),
323→        "/threads" => cmd_list_threads(ctx),
324→        "/thread" => cmd_create_thread(ctx, arg),
325→        "/members" => cmd_list_members(ctx),
326→        "/react" => cmd_react(ctx, arg),
327→        "/agent" => cmd_register_agent(ctx, arg),
328→        "/who" => cmd_who(ctx),
329→        "/history" => cmd_history(ctx, arg),
330→        #[cfg(feature = "dm")]
331→        "/dm" => cmd_dm(ctx, arg),
332→        #[cfg(feature = "dm")]
333→        "/dms" => cmd_list_dms(ctx),
334→        #[cfg(feature = "dm")]
335→        "/dm-history" => cmd_dm_history(ctx, arg),
336→        _ => eprintln!("Unknown command: {cmd}. Type /help for available commands."),
337→    }
338→}
