784→#[cfg(feature = "dm")]
785→fn cmd_list_dms(ctx: &DbConnection) {
786→    let my_identity = ctx.identity();
787→    let mut convs: Vec<_> = ctx
788→        .db
789→        .direct_conversation()
790→        .iter()
791→        .filter(|c| c.participant_a == my_identity || c.participant_b == my_identity)
792→        .collect();
793→    convs.sort_by(|a, b| b.last_message_at.cmp(&a.last_message_at));
794→
795→    if convs.is_empty() {
796→        println!("No direct conversations.");
797→        return;
798→    }
799→
800→    println!("Direct Conversations:");
801→    for conv in &convs {
802→        let other = if conv.participant_a == my_identity {
803→            &conv.participant_b
804→        } else {
805→            &conv.participant_a
806→        };
807→        let other_name = user_display_name(ctx, other);
808→
809→        // Count unread messages
810→        let unread = ctx
811→            .db
812→            .direct_message()
813→            .iter()
814→            .filter(|m| m.conversation_id == conv.id && m.sender != my_identity && !m.read)
815→            .count();
