834→        eprintln!("Invalid conversation ID: {}", parts[0]);
835→        return;
836→    };
837→    let count: usize = parts.get(1).and_then(|s| s.parse().ok()).unwrap_or(25);
838→
839→    let conv = ctx.db.direct_conversation().id().find(&conv_id);
840→    if conv.is_none() {
841→        eprintln!("Conversation not found: {conv_id}");
842→        return;
843→    }
844→
845→    let mut msgs: Vec<_> = ctx
846→        .db
847→        .direct_message()
848→        .iter()
849→        .filter(|m| m.conversation_id == conv_id)
850→        .collect();
