853→        .iter()
854→        .rev()
855→        .take(count)
856→        .collect::<Vec<_>>()
857→        .into_iter()
858→        .rev()
859→        .collect();
860→
861→    if recent.is_empty() {
862→        println!("No messages in this conversation.");
863→        return;
864→    }
865→
866→    println!("--- DM History ({}) ---", recent.len());
867→    for msg in recent {
868→        let sender_name = user_display_name(ctx, &msg.sender);
869→        let edit_mark = if msg.edited_at.is_some() {
870→            " (edited)"
871→        } else {
872→            ""
873→        };
874→        let read_mark = if msg.read { "" } else { " [unread]" };
875→        println!(
876→            "  {}: {}{}{}",
877→            sender_name, msg.content, edit_mark, read_mark
878→        );
879→    }
880→    println!("--- End ---");
881→
882→    // Mark as read
883→    if let Err(e) = ctx.reducers.mark_dm_read(conv_id) {
884→        eprintln!("Failed to mark as read: {e}");
885→    }
886→}
