  1→use std::fs;
  2→use std::path::Path;
  3→use std::time::Duration;
  4→
  5→/// Check whether a daemon is already healthy at the given URL.
  6→async fn is_daemon_healthy(base_url: &str) -> bool {
  7→    daemon_health(base_url).await.is_some()
  8→}
  9→
 10→/// Probe the daemon's `/health` endpoint.
 11→/// Returns the reported version string on success, or `None` if unreachable.
 12→async fn daemon_health(base_url: &str) -> Option<String> {
 13→    let url = format!("{base_url}/health");
 14→    let client = reqwest::Client::builder()
 15→        .timeout(Duration::from_secs(2))
 16→        .build()
 17→        .ok()?;
 18→    let resp = client.get(&url).send().await.ok()?;
 19→    if !resp.status().is_success() {
 20→        return None;
 21→    }
 22→    let body: serde_json::Value = resp.json().await.ok()?;
 23→    // Old daemons without a version field return None here — treated as outdated.
 24→    body.get("version")
 25→        .and_then(serde_json::Value::as_str)
 26→        .map(str::to_string)
 27→}
 28→
 29→/// Check if a PID file exists and the process is alive.
 30→/// Returns `Some(pid)` if alive, `None` if dead or no PID file.
 31→pub fn check_existing_pid(data_dir: &Path) -> Option<u32> {
 32→    let pid_path = data_dir.join("daemon.pid");
 33→    let raw = fs::read_to_string(&pid_path).ok()?;
 34→    let pid: u32 = raw.trim().parse().ok()?;
 35→
 36→    if is_process_alive(pid) {
 37→        Some(pid)
 38→    } else {
 39→        tracing::warn!(pid, "Stale daemon.pid found (process dead), removing");
 40→        let _ = fs::remove_file(&pid_path);
 41→        None
 42→    }
 43→}
 44→
 45→/// Check if a process with the given PID is alive using `kill -0`.
 46→#[cfg(unix)]
 47→pub fn is_process_alive(pid: u32) -> bool {
 48→    std::process::Command::new("kill")
 49→        .args(["-0", &pid.to_string()])
 50→        .stdout(std::process::Stdio::null())
 51→        .stderr(std::process::Stdio::null())
 52→        .status()
 53→        .is_ok_and(|s| s.success())
 54→}
 55→
 56→#[cfg(not(unix))]
 57→pub fn is_process_alive(_pid: u32) -> bool {
 58→    // On non-Unix, we can't cheaply check — assume alive if PID file exists.
 59→    true
 60→}
 61→
 62→/// Remove the daemon.pid file (called on graceful shutdown).
 63→pub fn remove_pid_file(data_dir: &Path) {
 64→    let pid_path = data_dir.join("daemon.pid");
 65→    if pid_path.exists() {
 66→        let _ = fs::remove_file(&pid_path);
 67→        tracing::info!("Removed daemon.pid");
 68→    }
 69→}
 70→
 71→/// Stop a running daemon by sending SIGTERM and waiting for exit.
 72→pub async fn stop_daemon(data_dir: &Path, port: u16) -> anyhow::Result<()> {
 73→    let base_url = format!("http://127.0.0.1:{port}");
 74→
 75→    // Check PID file first.
 76→    let Some(pid) = check_existing_pid(data_dir) else {
 77→        // No live process — check if the port is healthy anyway.
 78→        if is_daemon_healthy(&base_url).await {
 79→            anyhow::bail!(
 80→                "Daemon is healthy on {base_url} but no PID file found. Stop it manually."
 81→            );
 82→        }
 83→        anyhow::bail!("No running daemon found.");
 84→    };
 85→
 86→    // Send SIGTERM.
 87→    #[cfg(unix)]
 88→    {
 89→        let status = std::process::Command::new("kill")
 90→            .args([&pid.to_string()])
 91→            .stdout(std::process::Stdio::null())
 92→            .stderr(std::process::Stdio::null())
 93→            .status();
 94→        if status.is_err() || !status.unwrap().success() {
 95→            anyhow::bail!("Failed to send SIGTERM to PID {pid}");
 96→        }
 97→    }
 98→
 99→    #[cfg(not(unix))]
100→    {
101→        anyhow::bail!("stop is only supported on Unix systems");
102→    }
103→
104→    // Poll until process is dead (up to 10s).
105→    for _ in 0..50 {
106→        tokio::time::sleep(Duration::from_millis(200)).await;
107→        if !is_process_alive(pid) {
108→            remove_pid_file(data_dir);
109→            return Ok(());
110→        }
111→    }
112→
113→    anyhow::bail!("Daemon (PID {pid}) did not exit within 10 seconds");
114→}
115→
116→/// Ensure a daemon is running on the given port with a matching version.
117→///
118→/// 1. Probe `GET /health`. If healthy **and** version matches, return immediately.
119→/// 2. If healthy but version mismatches, stop the old daemon and respawn.
120→/// 3. Check `daemon.pid` — if process alive but health fails, wait briefly.
121→/// 4. If PID is stale, remove PID file and proceed.
122→/// 5. Spawn `arcan serve` as a detached child process.
123→/// 6. Poll `/health` until it succeeds (up to ~12 s).
124→pub async fn ensure_daemon(
125→    data_dir: &Path,
126→    port: u16,
127→    provider: Option<&str>,
128→    model: Option<&str>,
129→) -> anyhow::Result<String> {
130→    let base_url = format!("http://127.0.0.1:{port}");
131→    let current_version = env!("CARGO_PKG_VERSION");
132→
133→    if let Some(daemon_version) = daemon_health(&base_url).await {
134→        if daemon_version == current_version {
135→            tracing::info!("Daemon already running on {base_url} (v{daemon_version})");
136→            return Ok(base_url);
137→        }
138→        // Version mismatch — restart the daemon.
139→        tracing::warn!(
140→            daemon_version,
141→            current_version,
142→            "Daemon version mismatch, restarting"
143→        );
144→        if let Err(e) = stop_daemon(data_dir, port).await {
145→            tracing::warn!("Failed to stop outdated daemon: {e}, spawning anyway");
146→        }
147→    } else if is_daemon_healthy(&base_url).await {
148→        // Healthy but no version field — old daemon without version support.
149→        tracing::warn!("Daemon running without version info, restarting");
150→        if let Err(e) = stop_daemon(data_dir, port).await {
151→            tracing::warn!("Failed to stop old daemon: {e}, spawning anyway");
152→        }
153→    }
154→
155→    // Check PID file before spawning a new daemon.
156→    if let Some(pid) = check_existing_pid(data_dir) {
157→        // Process is alive but health check failed — it might be starting up.
158→        tracing::info!(pid, "Daemon process alive, waiting for health...");
159→        let delay = Duration::from_millis(200);
160→        for _ in 0..15 {
161→            tokio::time::sleep(delay).await;
162→            if let Some(v) = daemon_health(&base_url).await {
163→                if v == current_version {
164→                    tracing::info!("Existing daemon became healthy on {base_url} (v{v})");
165→                    return Ok(base_url);
166→                }
167→            }
168→        }
169→        // Still not healthy after 3s — the process might be stuck.
170→        tracing::warn!(
171→            pid,
172→            "Daemon process alive but not healthy/current after 3s, spawning new"
173→        );
174→    }
175→
176→    tracing::info!("Starting daemon on port {port}...");
177→
178→    fs::create_dir_all(data_dir)?;
179→    let log_file = fs::File::create(data_dir.join("daemon.log"))?;
180→    let stderr_log = log_file.try_clone()?;
181→
182→    // Resolve the current executable so `arcan serve` uses the same binary.
183→    let exe = std::env::current_exe()?;
184→
185→    let port_str = port.to_string();
186→    let dir_str = data_dir.to_string_lossy().to_string();
187→    let mut args = vec!["serve", "--port", &port_str, "--data-dir", &dir_str];
188→    if let Some(p) = provider {
189→        args.extend(["--provider", p]);
190→    }
191→    if let Some(m) = model {
192→        args.extend(["--model", m]);
193→    }
194→
195→    let child = std::process::Command::new(exe)
196→        .args(&args)
197→        .stdout(log_file)
198→        .stderr(stderr_log)
199→        .stdin(std::process::Stdio::null())
200→        .spawn()?;
201→
202→    // Write PID for later inspection / cleanup.
203→    fs::write(data_dir.join("daemon.pid"), child.id().to_string())?;
204→
205→    // Poll health endpoint.
206→    let max_retries = 60;
207→    let delay = Duration::from_millis(200);
208→    for i in 0..max_retries {
209→        tokio::time::sleep(delay).await;
210→        if is_daemon_healthy(&base_url).await {
211→            tracing::info!("Daemon healthy after {} ms", (i + 1) * 200);
212→            return Ok(base_url);
213→        }
214→    }
215→
216→    anyhow::bail!(
217→        "Daemon failed to become healthy within {}s. Check {}/daemon.log for details.",
218→        max_retries * 200 / 1000,
219→        data_dir.display()
220→    );
221→}
