15→impl ProviderFactory for ArcanProviderFactory {
16→    fn build(&self, spec: &str) -> Result<Arc<dyn Provider>, CoreError> {
17→        let (provider_name, model_override) = match spec.split_once(':') {
18→            Some((name, model)) => (name, Some(model)),
19→            None => (spec, None),
20→        };
21→
22→        match provider_name {
23→            "mock" => {
24→                tracing::info!("Provider switched to: mock");
25→                Ok(Arc::new(MockProvider))
26→            }
27→            "anthropic" => {
28→                let config = AnthropicConfig::from_resolved(model_override, None, None)
29→                    .map_err(|e| CoreError::Provider(e.to_string()))?;
30→                tracing::info!(model = %config.model, "Provider switched to: anthropic");
31→                Ok(Arc::new(AnthropicProvider::new(config)))
32→            }
33→            "openai" | "codex" | "openai-codex" => {
34→                let config = OpenAiConfig::openai_from_resolved(model_override, None, None)
35→                    .map_err(|e| CoreError::Provider(e.to_string()))?;
36→                tracing::info!(model = %config.model, "Provider switched to: openai");
37→                Ok(Arc::new(OpenAiCompatibleProvider::new(config)))
38→            }
39→            "ollama" => {
40→                let base_url = ollama::resolve_base_url();
41→                ollama::ensure_ollama_running(&base_url)?;
42→                let config =
43→                    OpenAiConfig::ollama_from_resolved(model_override, Some(&base_url), None, None)
44→                        .map_err(|e| CoreError::Provider(e.to_string()))?;
45→                tracing::info!(model = %config.model, base_url = %config.base_url, "Provider switched to: ollama");
46→                Ok(Arc::new(OpenAiCompatibleProvider::new(config)))
47→            }
48→            _ => Err(CoreError::Provider(format!(
49→                "unknown provider: \"{provider_name}\". Available: anthropic, openai, ollama, mock"
50→            ))),
51→        }
52→    }
53→
54→    fn available_providers(&self) -> Vec<String> {
55→        let mut providers = vec![
56→            "anthropic".to_string(),
57→            "openai".to_string(),
58→            "mock".to_string(),
59→        ];
60→
61→        let base_url = ollama::resolve_base_url();
62→        if ollama::is_ollama_running(&base_url) {
63→            match ollama::list_ollama_models(&base_url) {
64→                Ok(models) if !models.is_empty() => {
65→                    for model in models {
66→                        providers.push(format!("ollama:{model}"));
67→                    }
68→                }
69→                _ => {
70→                    providers.push("ollama".to_string());
71→                }
72→            }
73→        } else {
74→            providers.push("ollama".to_string());
75→        }
76→
77→        providers
78→    }
79→}
