  1→use crate::approval_gate::{ApprovalGate, ApprovalOutcome};
  2→use arcan_core::error::CoreError;
  3→use arcan_core::protocol::{AgentEvent, ToolAnnotations, ToolCall, ToolResult};
  4→use arcan_core::runtime::{Middleware, ToolContext};
  5→use lago_core::PolicyContext;
  6→use lago_core::event::{ApprovalDecision, PolicyDecisionKind, RiskLevel};
  7→use lago_policy::engine::PolicyEngine;
  8→use std::collections::HashMap;
  9→use std::sync::Arc;
 10→
 11→/// Arcan [`Middleware`] backed by lago's [`PolicyEngine`].
 12→///
 13→/// On every tool call, builds a [`PolicyContext`], evaluates the policy rules,
 14→/// and returns `Err(CoreError::Middleware)` when the decision is `Deny`.
 15→/// When `RequireApproval` is returned and a gate is configured, the middleware
 16→/// blocks until the approval is resolved (approved, denied, or timed out).
 17→/// Without a gate, `RequireApproval` falls back to `Deny`.
 18→pub struct LagoPolicyMiddleware {
 19→    engine: PolicyEngine,
 20→    /// Cached annotations per tool name, used to derive risk levels.
 21→    tool_annotations: HashMap<String, ToolAnnotations>,
 22→    /// Optional approval gate for interactive approval flow.
 23→    gate: Option<Arc<ApprovalGate>>,
 24→}
 25→
 26→impl LagoPolicyMiddleware {
 27→    pub fn new(engine: PolicyEngine, tool_annotations: HashMap<String, ToolAnnotations>) -> Self {
 28→        Self {
 29→            engine,
 30→            tool_annotations,
 31→            gate: None,
 32→        }
 33→    }
 34→
 35→    pub fn with_gate(
 36→        engine: PolicyEngine,
 37→        tool_annotations: HashMap<String, ToolAnnotations>,
 38→        gate: Arc<ApprovalGate>,
 39→    ) -> Self {
 40→        Self {
 41→            engine,
 42→            tool_annotations,
 43→            gate: Some(gate),
 44→        }
 45→    }
 46→
 47→    /// Derive a lago `RiskLevel` from arcan `ToolAnnotations`.
 48→    fn risk_level(&self, tool_name: &str) -> RiskLevel {
 49→        match self.tool_annotations.get(tool_name) {
 50→            Some(ann) if ann.requires_confirmation => RiskLevel::High,
 51→            Some(ann) if ann.destructive => RiskLevel::Medium,
 52→            Some(ann) if ann.read_only => RiskLevel::Low,
 53→            _ => RiskLevel::Low,
 54→        }
 55→    }
 56→
 57→    fn risk_level_str(&self, tool_name: &str) -> &'static str {
 58→        match self.risk_level(tool_name) {
 59→            RiskLevel::Low => "low",
 60→            RiskLevel::Medium => "medium",
 61→            RiskLevel::High => "high",
 62→            RiskLevel::Critical => "critical",
 63→        }
 64→    }
 65→
 66→    fn build_context(&self, ctx: &ToolContext, call: &ToolCall) -> PolicyContext {
 67→        PolicyContext {
 68→            tool_name: call.tool_name.clone(),
 69→            arguments: call.input.clone(),
 70→            category: None,
 71→            risk: Some(self.risk_level(&call.tool_name)),
 72→            session_id: ctx.session_id.clone(),
 73→            role: None,
 74→            sandbox_tier: None,
 75→        }
 76→    }
 77→}
 78→
 79→impl Middleware for LagoPolicyMiddleware {
 80→    fn pre_tool_call(&self, context: &ToolContext, call: &ToolCall) -> Result<(), CoreError> {
 81→        let policy_ctx = self.build_context(context, call);
 82→        let decision = self.engine.evaluate(&policy_ctx);
 83→
 84→        tracing::debug!(
 85→            tool = %call.tool_name,
 86→            decision = ?decision.decision,
 87→            rule_id = ?decision.rule_id,
 88→            "Policy evaluated"
 89→        );
 90→
 91→        match decision.decision {
 92→            PolicyDecisionKind::Allow => Ok(()),
 93→            PolicyDecisionKind::Deny => {
 94→                let reason = decision
 95→                    .explanation
 96→                    .unwrap_or_else(|| "denied by policy".to_string());
 97→                Err(CoreError::Middleware(format!(
 98→                    "tool '{}' blocked: {}",
 99→                    call.tool_name, reason
100→                )))
101→            }
102→            PolicyDecisionKind::RequireApproval => {
103→                let Some(gate) = &self.gate else {
104→                    // No gate configured: fall back to deny (backward compat)
105→                    let rule = decision.rule_id.unwrap_or_else(|| "unknown".to_string());
106→                    return Err(CoreError::Middleware(format!(
107→                        "tool '{}' requires approval (rule: {}) but no approval gate configured",
108→                        call.tool_name, rule
109→                    )));
110→                };
111→
112→                let approval_id = lago_core::ApprovalId::new().to_string();
113→                let risk = self.risk_level_str(&call.tool_name);
114→
115→                // Emit ApprovalRequested event
116→                gate.emit_event(AgentEvent::ApprovalRequested {
117→                    run_id: context.run_id.clone(),
118→                    session_id: context.session_id.clone(),
119→                    approval_id: approval_id.clone(),
120→                    call_id: call.call_id.clone(),
121→                    tool_name: call.tool_name.clone(),
122→                    arguments: call.input.clone(),
123→                    risk: risk.to_string(),
124→                });
125→
126→                // Register and block on oneshot
127→                let rx = gate.request_approval(&approval_id);
128→                let outcome = tokio::runtime::Handle::current().block_on(async {
129→                    rx.await.unwrap_or(ApprovalOutcome {
130→                        decision: ApprovalDecision::Timeout,
131→                        reason: None,
132→                    })
133→                });
134→
135→                // Emit ApprovalResolved event
136→                let decision_str = match outcome.decision {
137→                    ApprovalDecision::Approved => "approved",
138→                    ApprovalDecision::Denied => "denied",
139→                    ApprovalDecision::Timeout => "timeout",
140→                };
141→                gate.emit_event(AgentEvent::ApprovalResolved {
142→                    run_id: context.run_id.clone(),
143→                    session_id: context.session_id.clone(),
144→                    approval_id,
145→                    decision: decision_str.to_string(),
146→                    reason: outcome.reason.clone(),
147→                });
148→
149→                match outcome.decision {
150→                    ApprovalDecision::Approved => Ok(()),
151→                    _ => Err(CoreError::Middleware(format!(
152→                        "tool '{}' approval {}: {}",
153→                        call.tool_name,
154→                        decision_str,
155→                        outcome.reason.unwrap_or_default()
156→                    ))),
157→                }
158→            }
159→        }
160→    }
161→
162→    fn post_tool_call(
163→        &self,
164→        _context: &ToolContext,
165→        _result: &ToolResult,
166→    ) -> Result<(), CoreError> {
167→        Ok(())
168→    }
169→}
