  1→use crate::port::{SpacesMessageType, SpacesPort};
  2→use arcan_core::error::CoreError;
  3→use arcan_core::protocol::ToolResult;
  4→use arcan_core::runtime::{Middleware, RunOutput, ToolContext};
  5→use std::sync::Arc;
  6→
  7→/// Middleware that logs agent tool activity and run summaries to a Spaces channel.
  8→///
  9→/// Posts `AgentEvent`-typed messages to the configured `agent_log_channel_id`.
 10→/// Errors from the port are swallowed (logged via `tracing::warn!`) — observability
 11→/// must never block the agent loop.
 12→pub struct SpacesActivityMiddleware {
 13→    port: Arc<dyn SpacesPort>,
 14→    agent_log_channel_id: u64,
 15→}
 16→
 17→impl SpacesActivityMiddleware {
 18→    pub fn new(port: Arc<dyn SpacesPort>, agent_log_channel_id: u64) -> Self {
 19→        Self {
 20→            port,
 21→            agent_log_channel_id,
 22→        }
 23→    }
 24→}
 25→
 26→impl Middleware for SpacesActivityMiddleware {
 27→    fn post_tool_call(&self, _context: &ToolContext, result: &ToolResult) -> Result<(), CoreError> {
 28→        let status = if result.is_error {
 29→            "failed"
 30→        } else {
 31→            "completed"
 32→        };
 33→        let content = format!("[agent] Tool '{}' {status}", result.tool_name);
 34→
 35→        if let Err(e) = self
 36→            .port
 37→            .send_message(self.agent_log_channel_id, &content, None, None)
 38→        {
 39→            tracing::warn!(
 40→                error = %e,
 41→                channel_id = self.agent_log_channel_id,
 42→                "SpacesActivityMiddleware: failed to log tool call"
 43→            );
 44→        }
 45→
 46→        Ok(())
 47→    }
 48→
 49→    fn on_run_finished(&self, output: &RunOutput) -> Result<(), CoreError> {
 50→        let content = format!(
 51→            "[agent] Run '{}' finished: {:?} (iterations: {})",
 52→            output.run_id,
 53→            output.reason,
 54→            output
 55→                .events
 56→                .iter()
 57→                .filter(|e| {
 58→                    matches!(e, arcan_core::protocol::AgentEvent::IterationStarted { .. })
 59→                })
 60→                .count()
 61→        );
 62→
 63→        if let Err(e) = self
 64→            .port
 65→            .send_message(self.agent_log_channel_id, &content, None, None)
 66→        {
 67→            tracing::warn!(
 68→                error = %e,
 69→                channel_id = self.agent_log_channel_id,
 70→                "SpacesActivityMiddleware: failed to log run finished"
 71→            );
 72→        }
 73→
 74→        Ok(())
 75→    }
 76→}
