165→        };
166→
167→        // Should return Ok even though the port fails
168→        let outcome = mw.post_tool_call(&ctx, &result);
169→        assert!(outcome.is_ok());
170→
171→        let output = RunOutput {
172→            run_id: "run-1".to_string(),
173→            session_id: "s1".to_string(),
174→            branch_id: "main".to_string(),
175→            events: vec![],
176→            messages: vec![],
177→            state: AppState::default(),
178→            reason: RunStopReason::Error,
179→            final_answer: None,
180→            total_usage: TokenUsage::default(),
181→        };
182→        let outcome = mw.on_run_finished(&output);
183→        assert!(outcome.is_ok());
184→    }
185→}
