 355→/// Build provider from resolved configuration.
 356→fn build_provider(resolved: &ResolvedConfig) -> anyhow::Result<Arc<dyn Provider>> {
 357→    let pc = resolved.provider_config.as_ref();
 358→
 359→    match resolved.provider.as_str() {
 360→        "mock" => {
 361→            tracing::warn!("Provider: MockProvider (forced via config)");
 362→            Ok(Arc::new(MockProvider))
 363→        }
 364→        "openai" | "codex" | "openai-codex" => {
 365→            // Try OAuth credential first, then fall back to env var / resolved config.
 366→            if let Some(p) = try_openai_oauth_provider() {
 367→                return Ok(p);
 368→            }
 369→            let config = arcan_provider::openai::OpenAiConfig::openai_from_resolved(
 370→                resolved.model.as_deref(),
 371→                pc.and_then(|p| p.base_url.as_deref()),
 372→                pc.and_then(|p| p.max_tokens),
 373→            )?;
 374→            tracing::info!(model = %config.model, "Provider: OpenAI");
 375→            Ok(Arc::new(
 376→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 377→            ))
 378→        }
 379→        "ollama" => {
 380→            let config = arcan_provider::openai::OpenAiConfig::ollama_from_resolved(
 381→                resolved.model.as_deref(),
 382→                pc.and_then(|p| p.base_url.as_deref()),
 383→                pc.and_then(|p| p.max_tokens),
 384→                pc.and_then(|p| p.enable_streaming),
 385→            )?;
 386→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
 387→            Ok(Arc::new(
 388→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 389→            ))
 390→        }
 391→        "anthropic" => {
 392→            let config = AnthropicConfig::from_resolved(
 393→                resolved.model.as_deref(),
 394→                pc.and_then(|p| p.base_url.as_deref()),
 395→                pc.and_then(|p| p.max_tokens),
 396→            )?;
 397→            tracing::info!(model = %config.model, "Provider: Anthropic");
 398→            Ok(Arc::new(AnthropicProvider::new(config)))
 399→        }
 400→        // Auto-detect: try providers in order
 401→        _ => {
 402→            if let Ok(config) = AnthropicConfig::from_env() {
 403→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
 404→                Ok(Arc::new(AnthropicProvider::new(config)))
 405→            } else if let Some(p) = try_openai_oauth_provider() {
 406→                Ok(p)
 407→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
 408→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
 409→                Ok(Arc::new(
 410→                    arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 411→                ))
 412→            } else {
 413→                tracing::warn!(
 414→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
 415→                );
 416→                Ok(Arc::new(MockProvider))
 417→            }
 418→        }
 419→    }
 420→}
