 586→async fn run_chat(
 587→    data_dir: PathBuf,
 588→    resolved: &ResolvedConfig,
 589→    session: Option<String>,
 590→    url: Option<String>,
 591→) -> anyhow::Result<()> {
 592→    // Ensure daemon is running first to avoid redb lock conflicts.
 593→    let base_url = match url {
 594→        Some(u) => u,
 595→        None => {
 596→            daemon::ensure_daemon(
 597→                &data_dir,
 598→                resolved.port,
 599→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 600→                resolved.model.as_deref(),
 601→            )
 602→            .await?
 603→        }
 604→    };
 605→
 606→    // Resolve session via API (no direct journal access).
 607→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 608→    tracing::info!(session = %session, "launching TUI");
 609→
 610→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 611→        tracing::warn!(%error, "failed to persist last_session hint");
 612→    }
 613→
 614→    arcan_tui::run_tui(base_url, session).await
 615→}
